const express = require('express');
const axios = require('axios');

const app = express();
const port = 3000;

app.use(express.json());

app.post('/verify-license', async (req, res) => {
  try {
    const { license_number } = req.body;
    const payload = { number: license_number || "DXG100" };

    const response = await axios.post('https://api.prembly.com/verification/drivers_license', payload, {
      headers: {
        'app-id': process.env.PREMBLY_APP_ID,
        'x-api-key': process.env.PREMBLY_API_KEY
      }
    });

    res.json(response.data);
  } catch (error) {
    if (error.response) {
      res.status(error.response.status).json(error.response.data);
    } else {
      res.status(500).json({ error: 'Internal Server Error' });
    }
  }
});

app.listen(port, () => {
  console.log(`Server listening at http://localhost:${port}`);
});

